mapper.select:
select comments.*, user.name as userName, user.avatar as userAvatar, article.title as relName from `comments`
left join `user` on comments.user_id = user.id
left join `article` on comments.rel_id = article.id

     and article.title like concat('%', #{relName}, '%')
     and comments.content like concat('%', #{content}, '%')
     and comments.user_id = #{userId}
     and comments.rel_id = #{relId}
     and comments.fid = #{fid}

order by comments.id desc
